doc-pdf-gen.outputSchema:
z.object({
  success: z.boolean(),
  filePath: z.string().optional(),
  pages: z.number().int().optional(),
  fileSize: z.number().int().optional()
})

comms-stt.outputSchema:
z.object({
  success: z.boolean(),
  text: z.string().optional(),
  segments: z.array(z.object({
    startTime: z.number(),
    endTime: z.number(),
    text: z.string(),
    speaker: z.string().optional(),
    confidence: z.number()
  })).optional(),
  durationMs: z.number().int().optional(),
  speakers: z.array(z.string()).optional()
})

ai-embeddings.outputSchema:
z.object({
  success: z.boolean(),
  embeddings: z.array(z.array(z.number())).optional(),
  dimensions: z.number().int().optional(),
  model: z.string().optional(),
  similarities: z.array(z.object({
    text: z.string(),
    score: z.number(),
    index: z.number().int()
  })).optional(),
  searchResults: z.array(z.object({
    text: z.string(),
    score: z.number(),
    metadata: z.record(z.any()).optional()
  })).optional()
})

ai-sentiment.outputSchema:
z.object({
  success: z.boolean(),
  sentiment: z.object({
    score: z.number(),
    label: z.enum(['positive', 'negative', 'neutral', 'mixed']),
    confidence: z.number()
  }).optional(),
  emotions: z.object({
    joy: z.number(),
    sadness: z.number(),
    anger: z.number(),
    fear: z.number(),
    surprise: z.number()
  }).optional(),
  entities: z.array(z.object({
    name: z.string(),
    type: z.string(),
    confidence: z.number(),
    mentions: z.array(z.object({ text: z.string(), position: z.object({ start: z.number(), end: z.number() }) }))
  })).optional(),
  results: z.array(z.object({ text: z.string(), sentiment: z.any() })).optional()
})

data-etl.inputSchema:
z.object({
  action: z.enum(['extract', 'transform', 'load', 'run-pipeline', 'schedule', 'validate']).describe('ETL action'),
  pipelineName: z.string().optional().describe('Pipeline name'),
  source: z.object({
    type: z.enum(['csv', 'json', 'xml', 'database', 'api', 's3']),
    connection: z.string().optional(),
    path: z.string().optional(),
    query: z.string().optional()
  }).optional().describe('Data source configuration'),
  destination: z.object({
    type: z.enum(['csv', 'json', 'database', 's3', 'bigquery']),
    connection: z.string().optional(),
    path: z.string().optional(),
    table: z.string().optional()
  }).optional().describe('Data destination configuration'),
  transformations: z.array(z.object({
    type: z.string(),
    config: z.record(z.any())
  })).optional().describe('Transformations to apply'),
  schedule: z.string().optional().describe('Cron schedule expression')
})

analytics-bi.outputSchema:
z.object({
  success: z.boolean(),
  reportId: z.string().optional(),
  data: z.array(z.record(z.any())).optional(),
  summary: z.object({
    totalEvents: z.number().int().optional(),
    uniqueUsers: z.number().int().optional(),
    conversionRate: z.number().optional()
  }).optional(),
  funnel: z.array(z.object({ step: z.string(), users: z.number().int(), conversion: z.number() })).optional(),
  abTest: z.object({
    winner: z.string().optional(),
    confidence: z.number().optional(),
    results: z.array(z.object({ variant: z.string(), metric: z.number(), improvement: z.number() })).optional()
  }).optional()
})

loc-maps.outputSchema:
z.object({
  success: z.boolean(),
  results: z.array(z.object({
    formattedAddress: z.string(),
    coordinates: z.object({ lat: z.number(), lng: z.number() }),
    placeId: z.string().optional()
  })).optional(),
  routes: z.array(z.object({
    distance: z.string(),
    duration: z.string(),
    polyline: z.string().optional()
  })).optional(),
  matrix: z.array(z.array(z.object({ distance: z.string(), duration: z.string() }))).optional(),
  insideGeofence: z.boolean().optional()
})

iot-hardware.outputSchema:
z.object({
  success: z.boolean(),
  devices: z.array(z.object({
    id: z.string(), name: z.string(), type: z.string(), status: z.enum(['online', 'offline', 'error']),
    lastSeen: z.string(), battery: z.number().optional()
  })).optional(),
  sensorReading: z.object({
    type: z.string(), value: z.number(), unit: z.string(), timestamp: z.string()
  }).optional(),
  telemetry: z.array(z.object({ timestamp: z.string(), metrics: z.record(z.number()) })).optional(),
  commandResponse: z.any().optional()
})

math-science.outputSchema:
z.object({
  success: z.boolean(),
  result: z.any().optional(),
  latexRendered: z.string().optional(),
  statistics: z.object({
    mean: z.number().optional(), median: z.number().optional(), stdDev: z.number().optional(),
    min: z.number().optional(), max: z.number().optional(), variance: z.number().optional()
  }).optional(),
  graphMetrics: z.object({ nodes: z.number().int(), edges: z.number().int(), density: z.number().optional(), components: z.number().int().optional() }).optional(),
  moleculeImage: z.string().optional(),
  plotPath: z.string().optional(),
  conversion: z.object({ value: z.number(), from: z.string(), to: z.string(), result: z.number() }).optional()
})
